1139 /// Find the ComputeReductionResult recipe for \p PhiR, looking through selects
1140 /// inserted for predicated reductions or tail folding.
1141 static VPInstruction *findComputeReductionResult(VPReductionPHIRecipe *PhiR) {
1142   VPValue *BackedgeVal = PhiR->getBackedgeValue();
1143   if (auto *Res =
1144           findUserOf<VPInstruction::ComputeReductionResult>(BackedgeVal))
1145     return Res;
1146 
1147   // Look through selects inserted for tail folding or predicated reductions.
1148   VPRecipeBase *SelR =
1149       findUserOf(BackedgeVal, m_Select(m_VPValue(), m_VPValue(), m_VPValue()));
1150   if (!SelR)
1151     return nullptr;
1152   return findUserOf<VPInstruction::ComputeReductionResult>(
1153       cast<VPSingleDefRecipe>(SelR));
1154 }
1155 
1156 /// Find and return the final select instruction of the FindIV result pattern
1157 /// for the given \p BackedgeVal:
1158 /// select(icmp ne ComputeReductionResult(ReducedIV), Sentinel),
1159 ///        ComputeReductionResult(ReducedIV), Start.
1160 static VPInstruction *findFindIVSelect(VPValue *BackedgeVal) {
1161   return cast<VPInstruction>(
1162       vputils::findRecipe(BackedgeVal, [BackedgeVal](VPRecipeBase *R) {
1163         auto *VPI = dyn_cast<VPInstruction>(R);
1164         return VPI &&
1165                matchFindIVResult(VPI, m_Specific(BackedgeVal), m_VPValue());
1166       }));
1167 }
