1001 void VPlanTransforms::addMinimumIterationCheck(
1002     VPlan &Plan, ElementCount VF, unsigned UF,
1003     ElementCount MinProfitableTripCount, bool RequiresScalarEpilogue,
1004     bool TailFolded, bool CheckNeededWithTailFolding, Loop *OrigLoop,
1005     const uint32_t *MinItersBypassWeights, DebugLoc DL,
1006     PredicatedScalarEvolution &PSE) {
1007   // Generate code to check if the loop's trip count is less than VF * UF, or
1008   // equal to it in case a scalar epilogue is required; this implies that the
1009   // vector trip count is zero. This check also covers the case where adding one
1010   // to the backedge-taken count overflowed leading to an incorrect trip count
1011   // of zero. In this case we will also jump to the scalar loop.
1012   CmpInst::Predicate CmpPred =
1013       RequiresScalarEpilogue ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_ULT;
1014   // If tail is to be folded, vector loop takes care of all iterations.
1015   VPValue *TripCountVPV = Plan.getTripCount();
1016   const SCEV *TripCount = vputils::getSCEVExprForVPValue(TripCountVPV, PSE);
1017   Type *TripCountTy = TripCount->getType();
1018   ScalarEvolution &SE = *PSE.getSE();
1019   auto GetMinTripCount = [&]() -> const SCEV * {
1020     // Compute max(MinProfitableTripCount, UF * VF) and return it.
1021     const SCEV *VFxUF =
1022         SE.getElementCount(TripCountTy, (VF * UF), SCEV::FlagNUW);
1023     if (UF * VF.getKnownMinValue() >=
1024         MinProfitableTripCount.getKnownMinValue()) {
1025       // TODO: SCEV should be able to simplify test.
1026       return VFxUF;
1027     }
1028     const SCEV *MinProfitableTripCountSCEV =
1029         SE.getElementCount(TripCountTy, MinProfitableTripCount, SCEV::FlagNUW);
1030     return SE.getUMaxExpr(MinProfitableTripCountSCEV, VFxUF);
1031   };
1032 
1033   VPBasicBlock *EntryVPBB = Plan.getEntry();
1034   VPBuilder Builder(EntryVPBB);
1035   VPValue *TripCountCheck = Plan.getFalse();
1036   const SCEV *Step = GetMinTripCount();
1037   if (TailFolded) {
1038     if (CheckNeededWithTailFolding) {
1039       // vscale is not necessarily a power-of-2, which means we cannot guarantee
1040       // an overflow to zero when updating induction variables and so an
1041       // additional overflow check is required before entering the vector loop.
1042 
1043       VPValue *StepVPV = Builder.createExpandSCEV(Step);
1044 
1045       // Get the maximum unsigned value for the type.
1046       VPValue *MaxUIntTripCount =
1047           Plan.getConstantInt(cast<IntegerType>(TripCountTy)->getMask());
1048       VPValue *DistanceToMax = Builder.createNaryOp(
1049           Instruction::Sub, {MaxUIntTripCount, TripCountVPV},
1050           DebugLoc::getUnknown());
1051 
1052       // Don't execute the vector loop if (UMax - n) < (VF * UF).
1053       // FIXME: Should only check VF * UF, but currently checks Step=max(VF*UF,
1054       // minProfitableTripCount).
1055       TripCountCheck =
1056           Builder.createICmp(ICmpInst::ICMP_ULT, DistanceToMax, StepVPV, DL);
1057     } else {
1058       // TripCountCheck = false, folding tail implies positive vector trip
1059       // count.
1060     }
1061   } else {
1062     // TODO: Emit unconditional branch to vector preheader instead of
1063     // conditional branch with known condition.
1064     TripCount = SE.applyLoopGuards(TripCount, OrigLoop);
1065     // Check if the trip count is < the step.
1066     if (SE.isKnownPredicate(CmpPred, TripCount, Step)) {
1067       // TODO: Ensure step is at most the trip count when determining max VF and
1068       // UF, w/o tail folding.
1069       TripCountCheck = Plan.getTrue();
1070     } else if (!SE.isKnownPredicate(CmpInst::getInversePredicate(CmpPred),
1071                                     TripCount, Step)) {
1072       // Generate the minimum iteration check only if we cannot prove the
1073       // check is known to be true, or known to be false.
1074       VPValue *MinTripCountVPV = Builder.createExpandSCEV(Step);
1075       TripCountCheck = Builder.createICmp(
1076           CmpPred, TripCountVPV, MinTripCountVPV, DL, "min.iters.check");
1077     } // else step known to be < trip count, use TripCountCheck preset to false.
1078   }
1079   VPInstruction *Term =
1080       Builder.createNaryOp(VPInstruction::BranchOnCond, {TripCountCheck}, DL);
1081   if (MinItersBypassWeights) {
1082     MDBuilder MDB(Plan.getContext());
1083     MDNode *BranchWeights = MDB.createBranchWeights(
1084         ArrayRef(MinItersBypassWeights, 2), /*IsExpected=*/false);
1085     Term->setMetadata(LLVMContext::MD_prof, BranchWeights);
1086   }
1087 }
