1169 bool VPlanTransforms::handleMaxMinNumReductions(VPlan &Plan) {
1170   auto GetMinOrMaxCompareValue =
1171       [](VPReductionPHIRecipe *RedPhiR) -> VPValue * {
1172     auto *MinOrMaxR =
1173         dyn_cast_or_null<VPRecipeWithIRFlags>(RedPhiR->getBackedgeValue());
1174     if (!MinOrMaxR)
1175       return nullptr;
1176 
1177     // Check that MinOrMaxR is a VPWidenIntrinsicRecipe or VPReplicateRecipe
1178     // with an intrinsic that matches the reduction kind.
1179     Intrinsic::ID ExpectedIntrinsicID =
1180         getMinMaxReductionIntrinsicOp(RedPhiR->getRecurrenceKind());
1181     if (!match(MinOrMaxR, m_Intrinsic(ExpectedIntrinsicID)))
1182       return nullptr;
1183 
1184     if (MinOrMaxR->getOperand(0) == RedPhiR)
1185       return MinOrMaxR->getOperand(1);
1186 
1187     assert(MinOrMaxR->getOperand(1) == RedPhiR &&
1188            "Reduction phi operand expected");
1189     return MinOrMaxR->getOperand(0);
1190   };
1191 
1192   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
1193   SmallVector<std::pair<VPReductionPHIRecipe *, VPValue *>>
1194       MinOrMaxNumReductionsToHandle;
1195   bool HasUnsupportedPhi = false;
1196   for (auto &R : LoopRegion->getEntryBasicBlock()->phis()) {
1197     if (isa<VPCanonicalIVPHIRecipe, VPWidenIntOrFpInductionRecipe>(&R))
1198       continue;
1199     auto *Cur = dyn_cast<VPReductionPHIRecipe>(&R);
1200     if (!Cur) {
1201       // TODO: Also support fixed-order recurrence phis.
1202       HasUnsupportedPhi = true;
1203       continue;
1204     }
1205     if (!RecurrenceDescriptor::isFPMinMaxNumRecurrenceKind(
1206             Cur->getRecurrenceKind())) {
1207       HasUnsupportedPhi = true;
1208       continue;
1209     }
1210 
1211     VPValue *MinOrMaxOp = GetMinOrMaxCompareValue(Cur);
1212     if (!MinOrMaxOp)
1213       return false;
1214 
1215     MinOrMaxNumReductionsToHandle.emplace_back(Cur, MinOrMaxOp);
1216   }
1217 
1218   if (MinOrMaxNumReductionsToHandle.empty())
1219     return true;
1220 
1221   // We won't be able to resume execution in the scalar tail, if there are
1222   // unsupported header phis or there is no scalar tail at all, due to
1223   // tail-folding.
1224   if (HasUnsupportedPhi || !Plan.hasScalarTail())
1225     return false;
1226 
1227   /// Check if the vector loop of \p Plan can early exit and restart
1228   /// execution of last vector iteration in the scalar loop. This requires all
1229   /// recipes up to early exit point be side-effect free as they are
1230   /// re-executed. Currently we check that the loop is free of any recipe that
1231   /// may write to memory. Expected to operate on an early VPlan w/o nested
1232   /// regions.
1233   for (VPBlockBase *VPB : vp_depth_first_shallow(
1234            Plan.getVectorLoopRegion()->getEntryBasicBlock())) {
1235     auto *VPBB = cast<VPBasicBlock>(VPB);
1236     for (auto &R : *VPBB) {
1237       if (R.mayWriteToMemory() && !match(&R, m_BranchOnCount()))
1238         return false;
1239     }
1240   }
1241 
1242   VPBasicBlock *LatchVPBB = LoopRegion->getExitingBasicBlock();
1243   VPBuilder LatchBuilder(LatchVPBB->getTerminator());
1244   VPValue *AllNaNLanes = nullptr;
1245   SmallPtrSet<VPValue *, 2> RdxResults;
1246   for (const auto &[_, MinOrMaxOp] : MinOrMaxNumReductionsToHandle) {
1247     VPValue *RedNaNLanes =
1248         LatchBuilder.createFCmp(CmpInst::FCMP_UNO, MinOrMaxOp, MinOrMaxOp);
1249     AllNaNLanes = AllNaNLanes ? LatchBuilder.createOr(AllNaNLanes, RedNaNLanes)
