4895     return !W->getMask() && Member0Op == OpV;
4896   if (auto *IR = dyn_cast<VPInterleaveRecipe>(Member0OpR))
4897     return IR->getInterleaveGroup()->isFull() && IR->getVPValue(Idx) == OpV;
4898   return false;
