1190     // broadcasted element.
1191     case Instruction::ExtractElement:
1192       assert(!Ops[0]->getType()->isVectorTy() && "Live-ins should be scalar");
1193       return Ops[0];
1194     }
1195     return nullptr;
1196   };
1197 
1198   if (Value *V = FoldToIRValue())
1199     return R.getParent()->getPlan()->getOrAddLiveIn(V);
